#nullable enable // autogenerated

using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using PVZEngine.Definitions;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.spider_Animation)]
    public class Spider_AnimationBehaviour : EnemyCommonAnimationBehaviour
    {
        public Spider_AnimationBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override int GetAnimationState(int state)
        {
            switch (state)
            {
                case STATE_CLIMB:
                    return ANIMATION_STATE_IDLE;
            }
            return base.GetAnimationState(state);
        }
        public const int STATE_CLIMB = VanillaEnemyStates.SPIDER_CLIMB;
    }
}
